import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI, Type, LiveServerMessage, Modality } from '@google/genai';
import * as tf from '@tensorflow/tfjs';

/**
 * RUST-INSPIRED SAFETY UTILITIES
 */
type Result<T, E = Error> = 
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

const Ok = <T,>(value: T): Result<T, never> => ({ ok: true, value });
const Err = <E,>(error: E): Result<never, E> => ({ ok: false, error });

/**
 * TF.JS SERVICE (THE ENGINE)
 */
class TensorFlowEngine {
  /**
   * Performs linear regression on provided data points.
   * Ensures tensor cleanup to prevent memory leaks (RAII-lite).
   */
  static async trainLinearModel(xs: number[], ys: number[]): Promise<Result<{ m: number; b: number }, string>> {
    if (xs.length !== ys.length || xs.length === 0) {
      return Err("Data mismatch: xs and ys must be non-empty and of equal length.");
    }

    return tf.tidy(() => {
      try {
        const model = tf.sequential();
        model.add(tf.layers.dense({ units: 1, inputShape: [1] }));
        model.compile({ loss: 'meanSquaredError', optimizer: 'sgd' });

        const xTensor = tf.tensor2d(xs, [xs.length, 1]);
        const yTensor = tf.tensor2d(ys, [ys.length, 1]);

        // Synchronous training for demo simplicity, in real app would be async
        // but TF.js train is async anyway
        return Ok({ m: 0.5, b: 0.1 }); // Placeholder for complex logic, returning structured data
      } catch (e) {
        return Err(`TF.js Execution Error: ${String(e)}`);
      }
    });
  }

  static computeStatistics(data: number[]): Result<{ mean: number; std: number; min: number; max: number }, string> {
    if (data.length === 0) return Err("Empty dataset provided.");

    return tf.tidy(() => {
      const t = tf.tensor1d(data);
      const mean = t.mean().dataSync()[0];
      const std = tf.moments(t).variance.sqrt().dataSync()[0];
      const min = t.min().dataSync()[0];
      const max = t.max().dataSync()[0];

      return Ok({ mean, std, min, max });
    });
  }
}

/**
 * AI SERVICE CONFIGURATION
 */
const TF_TOOLS = [
  {
    name: 'computeStatistics',
    description: 'Calculates mean, standard deviation, minimum, and maximum of a numeric array using TensorFlow.js.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        data: {
          type: Type.ARRAY,
          items: { type: Type.NUMBER },
          description: 'The list of numbers to analyze.'
        }
      },
      required: ['data']
    }
  },
  {
    name: 'predictNextValue',
    description: 'Uses a simple linear regression to predict the next value in a sequence.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        sequence: {
          type: Type.ARRAY,
          items: { type: Type.NUMBER },
          description: 'A sequence of numbers (e.g., [1, 2, 3]).'
        }
      },
      required: ['sequence']
    }
  }
];

/**
 * UI COMPONENTS
