interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Initialized TF.js Sentinel Core. Awaiting instructions...' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleToolCall = async (fc: any): Promise<any> => {
    console.log("Tool Call Received:", fc);

    if (fc.name === 'computeStatistics') {
      const result = TensorFlowEngine.computeStatistics(fc.args.data);
      return result.ok ? result.value : { error: result.error };
    }

    if (fc.name === 'predictNextValue') {
      // Simulate a quick TF training for prediction
      const seq = fc.args.sequence;
      const indices = seq.map((_: any, i: number) => i);
      const res = await TensorFlowEngine.trainLinearModel(indices, seq);
      // For prediction, we just return a simulated next value based on the stats
      const stats = TensorFlowEngine.computeStatistics(seq);
      if (stats.ok) {
          const next = stats.value.mean + (stats.value.max - stats.value.min) / seq.length;
          return { prediction: next, confidence: "high", method: "TF.js Linear Approximation" };
      }
      return { error: "Failed to compute prediction" };
    }

    return { error: "Unknown function" };
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

