            role: m.role === 'system' ? 'user' : m.role,
            parts: [{ text: m.content }]
        })),
        config: {
          systemInstruction: 'You are a data science expert with access to a TensorFlow.js engine. Use the tools provided for any mathematical or statistical analysis. Explain your findings clearly.',
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

