interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Initialized TF.js Sentinel Core. \nModules Active: [LinearAlgebra, Statistics, AnomalyDetection].' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const model = 'gemini-3-pro-preview';

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleToolCall = async (fc: any): Promise<any> => {
    if (fc.name === 'performTensorMath') {
      const result = TensorFlowEngine.performTensorMath(fc.args.arrayA, fc.args.arrayB, fc.args.operation);
      if (result.ok) return result.value;
      return { error: result.error };
    }

    if (fc.name === 'cosineSimilarity') {
        const result = TensorFlowEngine.cosineSimilarity(fc.args.vectorA, fc.args.vectorB);
        if (result.ok) return result.value;
        return { error: result.error };
    }

    if (fc.name === 'detectOutliers') {
        const threshold = fc.args.threshold || 2;
        const result = TensorFlowEngine.detectOutliers(fc.args.data, threshold);
        if (result.ok) return result.value;
        return { error: result.error };
    }

    if (fc.name === 'computeStatistics') {
      const result = TensorFlowEngine.computeStatistics(fc.args.data);
      if (result.ok) return result.value;
      return { error: result.error };
    }

    if (fc.name === 'predictNextValue') {
      const seq = fc.args.sequence;
      const stats = TensorFlowEngine.computeStatistics(seq);
      if (stats.ok) {
        const next = stats.value.mean + (stats.value.max - stats.value.min) / seq.length;
        return { prediction: next, confidence: "high", method: "TF.js Linear Approximation" };
      }
      return { error: stats.error };
    }

    return { error: "Unknown function" };
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
        })),
        config: {
          systemInstruction: 'You are Sentinel Core, a data analysis AI. You have access to TensorFlow.js tools. Use "detectOutliers" for finding anomalies, "cosineSimilarity" for comparing vectors, and "performTensorMath" for raw calculation. Be precise and technical.',
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

      const candidate = response.candidates[0];

      if (candidate.content.parts.some(p => p.functionCall)) {
          const functionCalls = candidate.content.parts.filter(p => p.functionCall).map(p => p.functionCall);
          setMessages(prev => [...prev, { role: 'system', content: `Executing Tensor Operations...`, isToolCall: true }]);

          const toolResponses = await Promise.all(functionCalls.map(async (fc) => {
            const result = await handleToolCall(fc);
            return { functionResponse: { name: fc.name, response: result } };
          }));

          const finalResponse = await ai.models.generateContent({
            model,
            contents: [
                ...messages.map(m => ({ role: m.role === 'system' ? 'user' : (m.role as any), parts: [{ text: m.content }] })),
                { role: 'user', parts: [{ text: userMsg.content }] },
                { role: 'model', parts: candidate.content.parts },
                { role: 'user', parts: toolResponses as any }
            ],
            config: { tools: [{ functionDeclarations: TF_TOOLS as any }] }
          });

          setMessages(prev => [...prev, { role: 'model', content: finalResponse.text || "Operations complete." }]);
      } else {
          setMessages(prev => [...prev, { role: 'model', content: response.text || "Process completed." }]);
      }

    } catch (error) {
      setMessages(prev => [...prev, { role: 'system', content: `ENGINE ERROR: ${String(error)}` }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-[#020617] p-4 md:p-8">
      <header className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-cyan-500/20 flex items-center justify-center border border-cyan-500/50 shadow-[0_0_15px_rgba(34,211,238,0.3)]">
                <span className="text-cyan-400 font-bold">TF</span>
            </div>
            <div>
                <h1 className="text-xl font-bold tracking-tight glow-text uppercase">Sentinel Core v3</h1>
                <p className="text-xs text-slate-500 mono">ANOMALY_SCAN // VECTOR_ANALYSIS</p>
            </div>
        </div>
        <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-cyan-500 animate-pulse"></div>
            <span className="text-xs text-cyan-500 mono uppercase tracking-widest">Tensor Engine Ready</span>
        </div>
      </header>

      <main className="flex-1 overflow-hidden flex flex-col glass rounded-2xl shadow-2xl relative border-slate-800">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 scroll-hide">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-xl p-4 ${
                m.role === 'user' 
                  ? 'bg-cyan-600/20 border border-cyan-500/30 text-cyan-50 shadow-lg' 
                  : m.role === 'system'
                  ? 'bg-slate-800/40 border border-slate-700/50 text-slate-500 mono text-[10px]'
                  : 'bg-slate-900/60 border border-slate-800 text-slate-200'
              }`}>
                {m.role === 'model' && <div className="text-[10px] text-cyan-500/70 mb-1 mono font-bold tracking-widest uppercase">System_Response</div>}
                <div className="whitespace-pre-wrap leading-relaxed">{m.content}</div>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-slate-900/60 border border-slate-800 rounded-xl p-4 flex gap-2 items-center">
                <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
