              className="flex-1 bg-slate-900/80 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-cyan-500/40 transition-all mono text-sm"
            />
