/**
 * RUST-INSPIRED SAFETY UTILITIES
 * Shared types for safe error handling across modules.
 */
export type Result<T, E = Error> = 
  | { readonly ok: true; readonly value: T; readonly error?: never }
  | { readonly ok: false; readonly error: E; readonly value?: never };

export const Ok = <T,>(value: T): Result<T, never> => ({ ok: true, value });
export const Err = <E,>(error: E): Result<never, E> => ({ ok: false, error });

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { TensorFlowEngine } from './engine';
import { TF_TOOLS } from './tools';

interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Initialized TF.js Sentinel Core. \nModules Active: [LinearAlgebra, Statistics, AnomalyDetection].' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const model = 'gemini-3-pro-preview';

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  const handleToolCall = async (fc: any): Promise<any> => {
    if (fc.name === 'performTensorMath') {
      const result = TensorFlowEngine.performTensorMath(fc.args.arrayA, fc.args.arrayB, fc.args.operation);
      if (result.ok === false) {
        return { error: result.error };
      }
      return result.value;
    }

    if (fc.name === 'cosineSimilarity') {
        const result = TensorFlowEngine.cosineSimilarity(fc.args.vectorA, fc.args.vectorB);
        if (result.ok === false) {
          return { error: result.error };
        }
        return result.value;
    }

    if (fc.name === 'detectOutliers') {
        const threshold = fc.args.threshold || 2;
        const result = TensorFlowEngine.detectOutliers(fc.args.data, threshold);
        if (result.ok === false) {
          return { error: result.error };
        }
        return result.value;
    }

    if (fc.name === 'computeStatistics') {
      const result = TensorFlowEngine.computeStatistics(fc.args.data);
      if (result.ok === false) {
        return { error: result.error };
      }
      return result.value;
    }

    if (fc.name === 'predictNextValue') {
      const seq = fc.args.sequence;
      const stats = TensorFlowEngine.computeStatistics(seq);
      if (stats.ok === false) {
        return { error: stats.error };
      }

      const next = stats.value.mean + (stats.value.max - stats.value.min) / seq.length;
      return { prediction: next, confidence: "high", method: "TF.js Linear Approximation" };
    }

    return { error: "Unknown function" };
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
