export type Result<T, E = Error> = 
  | { readonly ok: true; readonly value: T; readonly error?: never }
  | { readonly ok: false; readonly error: E; readonly value?: never };

export const Ok = <T,>(value: T): Result<T, never> => ({ ok: true, value });
export const Err = <E,>(error: E): Result<never, E> => ({ ok: false, error });

/**
 * REDUX/RXJS STYLE ACTIONS
 * Strongly typed actions for the Tensor Stream.
 */
export type TFAction = 
  | { type: 'MATH'; payload: { arrayA: number[]; arrayB: number[]; operation: 'add' | 'sub' | 'mul' | 'div' | 'dot' } }
  | { type: 'COSINE'; payload: { vectorA: number[]; vectorB: number[] } }
  | { type: 'OUTLIERS'; payload: { data: number[]; threshold: number } }
  | { type: 'STATS'; payload: { data: number[] } };

import { Subject, firstValueFrom, from, of } from 'rxjs';
import { filter, map, mergeMap, catchError, tap, share } from 'rxjs';
import { TensorFlowEngine } from './engine';
import { TFAction, Result, Err } from './types';

// Unique ID generator for stream correlation
const uuid = () => Math.random().toString(36).substring(2, 9);

interface StreamPacket {
  id: string;
  action: TFAction;
}

interface StreamResult {
  id: string;
  result: Result<any, string>;
}

class RxTensorFlowBridge {
  private _actionSubject = new Subject<StreamPacket>();

  // The Main Stream Pipeline
  // Actions go in -> Processed by TF -> Results come out
  public readonly resultStream$ = this._actionSubject.pipe(
    tap(packet => console.log(`[RxJS] Processing Action: ${packet.action.type}`, packet)),
    mergeMap(packet => {
      // Convert the synchronous/async engine call into an Observable
      return from(this._execute(packet.action)).pipe(
        map(result => ({ id: packet.id, result })),
        catchError(err => of({ 
          id: packet.id, 
          result: Err(`Stream Error: ${String(err)}`) 
        }))
      );
    }),
    share() // Share the subscription among listeners
  );

  constructor() {
    // Start the stream immediately to catch events (hot observable style)
    this.resultStream$.subscribe(); 
  }

  /**
   * Public API: Dispatch an action and await the specific result from the stream.
   * This bridges the gap between the Gemini "Await Tool Response" requirement
   * and the RxJS "Stream" architecture.
   */
  public async dispatch(action: TFAction): Promise<Result<any, string>> {
    const id = uuid();

    // 1. Create a promise that waits for the specific ID to appear in the result stream
    const resultPromise = firstValueFrom(
      this.resultStream$.pipe(
        filter(packet => packet.id === id),
        map(packet => packet.result)
      )
    );

    // 2. Push the action into the stream
    this._actionSubject.next({ id, action });

    // 3. Return the result (Gemini awaits this)
    return resultPromise;
  }

  // Internal Execution Router
  private async _execute(action: TFAction): Promise<Result<any, string>> {
    switch (action.type) {
      case 'MATH':
        return TensorFlowEngine.performTensorMath(
          action.payload.arrayA, 
          action.payload.arrayB, 
          action.payload.operation
        );
      case 'COSINE':
        return TensorFlowEngine.cosineSimilarity(
          action.payload.vectorA, 
          action.payload.vectorB
        );
      case 'OUTLIERS':
        return TensorFlowEngine.detectOutliers(
          action.payload.data, 
          action.payload.threshold
        );
      case 'STATS':
        return TensorFlowEngine.computeStatistics(
          action.payload.data
        );
      default:
        return Err("Unknown Action Type in Stream");
    }
  }
}

