import * as tf from '@tensorflow/tfjs';
import { Result, Ok, Err } from './types';

interface VectorRecord {
  id: string;
  text: string;
  vector: number[];
}

/**
 * TF.JS SERVICE (THE ENGINE)
 * Handles all tensor manipulations and mathematical computations.
 */
export class TensorFlowEngine {
  // Store the currently loaded model in memory
  private static activeModel: tf.LayersModel | null = null;
  // In-Memory Vector Database (Simulating LanceDB)
  private static vectorDb: VectorRecord[] = [];

  /**
   * Melakukan operasi matematika element-wise pada dua tensor.
   */
  static performTensorMath(a: number[], b: number[], operation: 'add' | 'sub' | 'mul' | 'div' | 'dot'): Result<{ result: number[] | number, shape: number[] }, string> {
    if (a.length !== b.length) {
      return Err(`Dimensi tidak cocok: Tensor A (${a.length}) dan B (${b.length}) harus memiliki ukuran yang sama.`);
    }

    try {
      return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        let res: tf.Tensor;

        if (operation === 'dot') {
            res = tf.dot(tA, tB);
            return Ok({
                result: res.dataSync()[0],
                shape: []
            });
        }

        switch (operation) {
          case 'add': res = tf.add(tA, tB); break;
          case 'sub': res = tf.sub(tA, tB); break;
          case 'mul': res = tf.mul(tA, tB); break;
          case 'div': res = tf.div(tA, tB); break;
          default: return Err("Operasi tidak dikenal.");
        }

        return Ok({
          result: Array.from(res.dataSync()),
          shape: res.shape
        });
      });
    } catch (e) {
      return Err(`Gagal memanipulasi tensor: ${String(e)}`);
    }
  }

  /**
   * Menghitung kemiripan kosinus (Cosine Similarity) antara dua vektor.
   * Nilai 1 berarti identik, 0 berarti ortogonal (tidak berhubungan), -1 berlawanan.
   */
  static cosineSimilarity(a: number[], b: number[]): Result<{ similarity: number }, string> {
     if (a.length !== b.length) return Err("Vector dimensions must match for similarity check.");

     return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        const dotProduct = tf.dot(tA, tB);
        const normA = tf.norm(tA);
        const normB = tf.norm(tB);

        // similarity = (A . B) / (||A|| * ||B||)
        const similarity = tf.div(dotProduct, tf.mul(normA, normB));
        return Ok({ similarity: similarity.dataSync()[0] });
     });
  }

  /**
   * Mendeteksi outlier (anomali) menggunakan metode Z-Score.
   * Data dianggap anomali jika nilainya > threshold standar deviasi dari rata-rata.
   */
  static detectOutliers(data: number[], threshold: number = 2): Result<{ outliers: number[], indices: number[] }, string> {
      if (data.length === 0) return Err("Data kosong.");

      return tf.tidy(() => {
          const t = tf.tensor1d(data);
          const moments = tf.moments(t);
          const mean = moments.mean;
          const std = moments.variance.sqrt();

          // Z-score = (x - mean) / std
          const zScores = tf.abs(tf.div(tf.sub(t, mean), std));

          // Masking: return 1 where zScore > threshold
          const mask = zScores.greater(threshold);

          // Async download is generally preferred but here we need sync for the tool return
          const maskData = mask.dataSync();
          const outliers: number[] = [];
          const indices: number[] = [];

          maskData.forEach((isOutlier, index) => {
              if (isOutlier) {
                  outliers.push(data[index]);
                  indices.push(index);
              }
          });

          return Ok({ outliers, indices });
      });
  }

  static computeStatistics(data: number[]): Result<{ mean: number; std: number; min: number; max: number }, string> {
    if (data.length === 0) return Err("Empty dataset provided.");

    return tf.tidy(() => {
      const t = tf.tensor1d(data);
      const mean = t.mean().dataSync()[0];
      const std = tf.moments(t).variance.sqrt().dataSync()[0];
      const min = t.min().dataSync()[0];
      const max = t.max().dataSync()[0];

      return Ok({ mean, std, min, max });
    });
  }

  // --- MODEL MANAGEMENT ---

  static async loadModel(url: string): Promise<Result<{ message: string }, string>> {
      try {
          // Dispose previous model if exists to free memory
          if (this.activeModel) {
              this.activeModel.dispose();
          }

          this.activeModel = await tf.loadLayersModel(url);
          return Ok({ message: `Model loaded successfully from ${url}` });
      } catch (e) {
          return Err(`Failed to load model: ${String(e)}. Ensure CORS is enabled on the server.`);
      }
  }

  static async createDemoModel(): Promise<Result<{ message: string; loss: number }, string>> {
      try {
          if (this.activeModel) this.activeModel.dispose();

          const model = tf.sequential();
          model.add(tf.layers.dense({ units: 1, inputShape: [1] }));
          model.compile({ loss: 'meanSquaredError', optimizer: 'sgd' });

          // Train a simple model: y = 2x - 1
          const xs = tf.tensor2d([-1, 0, 1, 2, 3, 4], [6, 1]);
          const ys = tf.tensor2d([-3, -1, 1, 3, 5, 7], [6, 1]);

          const h = await model.fit(xs, ys, { epochs: 250 });
          this.activeModel = model;

          xs.dispose();
          ys.dispose();

          return Ok({ 
            message: "Demo Linear Model (y = 2x - 1) trained and loaded.", 
            loss: h.history.loss[h.history.loss.length - 1] as number 
          });
      } catch (e) {
          return Err(`Failed to create demo model: ${String(e)}`);
      }
  }

  static runPrediction(input: number[]): Result<{ prediction: number[] }, string> {
      if (!this.activeModel) return Err("No model loaded. Please load or create a model first.");

      try {
          return tf.tidy(() => {
             const t = tf.tensor(input);
             // Ensure correct shape for simple models (batch size 1 if necessary)
             const inputTensor = t.shape.length === 1 ? t.expandDims(0) : t;

             const output = this.activeModel!.predict(inputTensor) as tf.Tensor;
             return Ok({ prediction: Array.from(output.dataSync()) });
          });
      } catch (e) {
          return Err(`Prediction failed: ${String(e)}`);
      }
  }

  // --- VECTOR DATABASE (LanceDB Simulation) ---

  static async insertVector(text: string, vector: number[]): Promise<Result<{ id: string, total_records: number }, string>> {
    try {
      const id = Math.random().toString(36).substring(7);
      this.vectorDb.push({ id, text, vector });
      return Ok({ id, total_records: this.vectorDb.length });
    } catch (e) {
      return Err(`Failed to insert into vector DB: ${String(e)}`);
    }
  }

  static async searchVector(queryVector: number[], topK: number = 3): Promise<Result<{ matches: { text: string, score: number }[] }, string>> {
    if (this.vectorDb.length === 0) return Err("Vector Database is empty.");

    return tf.tidy(() => {
      // 1. Prepare Tensors
      const vectors = this.vectorDb.map(r => r.vector);
      // Shape: [NumRecords, EmbeddingSize]
      const dbTensor = tf.tensor2d(vectors);
      // Shape: [EmbeddingSize]
      const queryTensor = tf.tensor1d(queryVector);

      // 2. Normalize Vectors (Cosine Similarity = Dot Product of Normalized Vectors)
      // Norm axis=1 for DB, standard norm for query
      const dbNorm = tf.norm(dbTensor, 2, 1).expandDims(1);
      const queryNorm = tf.norm(queryTensor);

      const normalizedDb = tf.div(dbTensor, dbNorm);
      const normalizedQuery = tf.div(queryTensor, queryNorm);

      // 3. Compute Dot Product
      // [N, D] @ [D, 1] -> [N, 1]
      const scores = tf.matMul(normalizedDb, normalizedQuery.expandDims(1)).flatten();

      // 4. Find Top K
      const k = Math.min(topK, this.vectorDb.length);
      const { values, indices } = tf.topk(scores, k);

      const topKIndices = indices.arraySync() as number[];
      const topKScores = values.arraySync() as number[];

      const matches = topKIndices.map((idx, i) => ({
        text: this.vectorDb[idx].text,
        score: topKScores[i]
      }));

      return Ok({ matches });
    });
  }
}

import { Subject, firstValueFrom, from, of } from 'rxjs';
import { filter, map, mergeMap, catchError, tap, share } from 'rxjs';
import { TensorFlowEngine } from './engine';
import { TFAction, Result, Err } from './types';

// Unique ID generator for stream correlation
const uuid = () => Math.random().toString(36).substring(2, 9);

interface StreamPacket {
  id: string;
  action: TFAction;
}

interface StreamResult {
  id: string;
  result: Result<any, string>;
}

class RxTensorFlowBridge {
  private _actionSubject = new Subject<StreamPacket>();

  // The Main Stream Pipeline
  // Actions go in -> Processed by TF -> Results come out
  public readonly resultStream$ = this._actionSubject.pipe(
    tap(packet => console.log(`[RxJS] Processing Action: ${packet.action.type}`, packet)),
    mergeMap(packet => {
      // Convert the synchronous/async engine call into an Observable
      return from(this._execute(packet.action)).pipe(
        map(result => ({ id: packet.id, result })),
        catchError(err => of({ 
          id: packet.id, 
          result: Err(`Stream Error: ${String(err)}`) 
        }))
      );
    }),
    share() // Share the subscription among listeners
  );

  constructor() {
    // Start the stream immediately to catch events (hot observable style)
    this.resultStream$.subscribe(); 
  }

  /**
   * Public API: Dispatch an action and await the specific result from the stream.
   * This bridges the gap between the Gemini "Await Tool Response" requirement
   * and the RxJS "Stream" architecture.
   */
  public async dispatch(action: TFAction): Promise<Result<any, string>> {
    const id = uuid();

    // 1. Create a promise that waits for the specific ID to appear in the result stream
    const resultPromise = firstValueFrom(
      this.resultStream$.pipe(
        filter(packet => packet.id === id),
        map(packet => packet.result)
      )
    );

    // 2. Push the action into the stream
    this._actionSubject.next({ id, action });

    // 3. Return the result (Gemini awaits this)
    return resultPromise;
  }

  // Internal Execution Router
  private async _execute(action: TFAction): Promise<Result<any, string>> {
    switch (action.type) {
      case 'MATH':
        return TensorFlowEngine.performTensorMath(
          action.payload.arrayA, 
          action.payload.arrayB, 
          action.payload.operation
        );
      case 'COSINE':
        return TensorFlowEngine.cosineSimilarity(
          action.payload.vectorA, 
          action.payload.vectorB
        );
      case 'OUTLIERS':
        return TensorFlowEngine.detectOutliers(
          action.payload.data, 
          action.payload.threshold
        );
      case 'STATS':
        return TensorFlowEngine.computeStatistics(
          action.payload.data
        );
      case 'LOAD_MODEL':
        return TensorFlowEngine.loadModel(action.payload.url);
      case 'CREATE_DEMO_MODEL':
        return TensorFlowEngine.createDemoModel();
      case 'PREDICT':
        return TensorFlowEngine.runPrediction(action.payload.input);
      case 'DB_INSERT':
        return TensorFlowEngine.insertVector(
          action.payload.text,
          action.payload.vector
        );
      case 'DB_SEARCH':
        return TensorFlowEngine.searchVector(
          action.payload.vector,
          action.payload.topK
        );
      default:
        return Err("Unknown Action Type in Stream");
    }
  }
}

// Singleton Instance
export const tfStream = new RxTensorFlowBridge();

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { tfStream } from './rx-engine';
import { TF_TOOLS } from './tools';

interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const MODELS = [
  { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro (Deep Logic)' },
  { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash (Fast)' },
];

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Initialized TF.js Sentinel Core. \nModules Active: [LinearAlgebra, Statistics, AnomalyDetection, ModelEngine, LanceDB].\nStream: RxJS Observable Active.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState(MODELS[0].id);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [messages]);

  // Helper to generate embeddings via Gemini API
  const getEmbedding = async (text: string): Promise<number[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = ai.models.getGenerativeModel({ model: 'text-embedding-004' });
    // Note: The @google/genai SDK v0.1+ syntax for embeddings:
    const result = await ai.models.embedContent({
        model: 'text-embedding-004',
        contents: text
    });
    return result.embedding.values;
  };

  // Handle Tool Calls via RxJS Dispatcher
  const handleToolCall = async (fc: any): Promise<any> => {
    let result;

    if (fc.name === 'performTensorMath') {
      result = await tfStream.dispatch({
        type: 'MATH',
        payload: {
          arrayA: fc.args.arrayA,
          arrayB: fc.args.arrayB,
          operation: fc.args.operation
        }
      });
    } else if (fc.name === 'cosineSimilarity') {
      result = await tfStream.dispatch({
        type: 'COSINE',
        payload: {
          vectorA: fc.args.vectorA,
          vectorB: fc.args.vectorB
        }
      });
    } else if (fc.name === 'detectOutliers') {
      result = await tfStream.dispatch({
        type: 'OUTLIERS',
        payload: {
          data: fc.args.data,
          threshold: fc.args.threshold || 2
        }
      });
    } else if (fc.name === 'computeStatistics') {
      result = await tfStream.dispatch({
        type: 'STATS',
        payload: {
          data: fc.args.data
        }
      });
    } else if (fc.name === 'predictNextValue') {
      const statsResult = await tfStream.dispatch({
        type: 'STATS',
        payload: { data: fc.args.sequence }
      });

      if (statsResult.ok === false) return { error: statsResult.error };

      const seq = fc.args.sequence;
      const next = statsResult.value.mean + (statsResult.value.max - statsResult.value.min) / seq.length;
      return { prediction: next, confidence: "high", method: "TF.js Linear Approximation (Stream)" };
    } else if (fc.name === 'loadModel') {
        result = await tfStream.dispatch({
            type: 'LOAD_MODEL',
            payload: { url: fc.args.url }
        });
    } else if (fc.name === 'createDemoModel') {
        result = await tfStream.dispatch({
            type: 'CREATE_DEMO_MODEL',
            payload: {}
        });
    } else if (fc.name === 'runPrediction') {
        result = await tfStream.dispatch({
            type: 'PREDICT',
            payload: { input: fc.args.input }
        });
    } else if (fc.name === 'storeMemory') {
        // RAG INSERT
        try {
            const vector = await getEmbedding(fc.args.text);
            result = await tfStream.dispatch({
                type: 'DB_INSERT',
                payload: { text: fc.args.text, vector }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else if (fc.name === 'recallMemory') {
        // RAG SEARCH
        try {
            const vector = await getEmbedding(fc.args.query);
            result = await tfStream.dispatch({
                type: 'DB_SEARCH',
                payload: { vector, topK: 3 }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else {
      return { error: "Unknown function" };
    }

    if (result.ok === false) {
      return { error: result.error };
    }
    return result.value;
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: selectedModel,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
        })),
        config: {
          // Enable Thinking Budget for complex reasoning
          thinkingConfig: { thinkingBudget: 2048 }, 
          systemInstruction: `
You are Sentinel Core v4.1, an advanced AI Data Scientist orchestrating a Reactive TensorFlow.js Engine and a Vector Database.

YOUR CAPABILITIES:
1.  **Thinking & Planning**: Plan complex analysis steps.
2.  **RxJS Pipeline**: Mathematical execution via streams.
3.  **TF.js Core**: Machine Learning and Calculations.
4.  **LanceDB (Vector DB)**: You have a long-term memory module.
    - Use 'storeMemory(text)' to save facts, context, or user preferences.
    - Use 'recallMemory(query)' to retrieve relevant info before answering questions about past context.

COMPLEX WORKFLOW RULES:
-   **Analyze First**: Statistics -> Outliers -> Recommendation.
-   **Model Training**: Create/Load -> Predict -> Report Loss.
-   **RAG (Retrieval Augmented Generation)**: 
    - If the user asks something you might have stored previously, use 'recallMemory' FIRST.
    - If the user provides a new important fact, use 'storeMemory'.
    - Example: "Ingat bahwa saya suka angka genap" -> storeMemory("User suka angka genap").
    - Example: "Apa yang saya suka?" -> recallMemory("Apa yang user suka?").

You are technical, precise, and prefer using tools over guessing.
          `,
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

      const candidate = response.candidates[0];

      if (candidate.content.parts.some(p => p.functionCall)) {
          const functionCalls = candidate.content.parts.filter(p => p.functionCall).map(p => p.functionCall);

          setMessages(prev => [...prev, { 
            role: 'system', 
            content: `🧠 Reasoning Complex Pipeline... \nDispatching ${functionCalls.length} Action(s) to RxJS Stream`, 
            isToolCall: true 
          }]);

          const toolResponses = await Promise.all(functionCalls.map(async (fc) => {
            const result = await handleToolCall(fc);
            return { functionResponse: { name: fc.name, response: result } };
          }));

          const finalResponse = await ai.models.generateContent({
            model: selectedModel,
            contents: [
                ...messages.map(m => ({ role: m.role === 'system' ? 'user' : (m.role as any), parts: [{ text: m.content }] })),
                { role: 'user', parts: [{ text: userMsg.content }] },
                { role: 'model', parts: candidate.content.parts },
                { role: 'user', parts: toolResponses as any }
            ],
            config: { 
                thinkingConfig: { thinkingBudget: 1024 }, // Reduced budget for final summary
                tools: [{ functionDeclarations: TF_TOOLS as any }] 
            }
          });

          setMessages(prev => [...prev, { role: 'model', content: finalResponse.text || "Operations complete." }]);
      } else {
          setMessages(prev => [...prev, { role: 'model', content: response.text || "Process completed." }]);
      }

    } catch (error) {
      setMessages(prev => [...prev, { role: 'system', content: `STREAM ERROR: ${String(error)}` }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-[#020617] p-4 md:p-8">
      <header className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-indigo-500/20 flex items-center justify-center border border-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                 {/* Brain Icon for Thinking */}
                <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                </svg>
            </div>
            <div className="w-10 h-10 rounded-lg bg-cyan-500/20 flex items-center justify-center border border-cyan-500/50 shadow-[0_0_15px_rgba(34,211,238,0.3)]">
                <span className="text-cyan-400 font-bold">TF</span>
            </div>
