import * as tf from '@tensorflow/tfjs';
import { Result, Ok, Err } from './types';

interface VectorRecord {
  id: string;
  text: string;
  vector: number[];
}

/**
 * TF.JS SERVICE (THE ENGINE)
 * Handles all tensor manipulations and mathematical computations.
 */
export class TensorFlowEngine {
  // Store the currently loaded model in memory
  private static activeModel: tf.LayersModel | null = null;
  // In-Memory Vector Database (Simulating LanceDB)
  private static vectorDb: VectorRecord[] = [];
  private static dbLoaded: boolean = false;
  private static DB_KEY = 'SENTINEL_VECTOR_DB_V1';

  private static ensureDbLoaded() {
      if (!this.dbLoaded && typeof window !== 'undefined') {
          try {
              const saved = localStorage.getItem(this.DB_KEY);
              if (saved) {
                  this.vectorDb = JSON.parse(saved);
                  console.log(`[Engine] Loaded ${this.vectorDb.length} memories from storage.`);
              }
          } catch (e) {
              console.error("[Engine] Failed to load DB", e);
          }
          this.dbLoaded = true;
      }
  }

  private static saveDb() {
      if (typeof window !== 'undefined') {
          try {
              // Limit check: Simple safeguard for LocalStorage (5MB limit)
              // If too large, keep only the last 50 items
              if (this.vectorDb.length > 50) {
                  this.vectorDb = this.vectorDb.slice(-50);
              }
              localStorage.setItem(this.DB_KEY, JSON.stringify(this.vectorDb));
          } catch (e) {
              console.error("[Engine] Failed to save DB", e);
          }
      }
  }

  /**
   * Melakukan operasi matematika element-wise pada dua tensor.
   */
  static performTensorMath(a: number[], b: number[], operation: 'add' | 'sub' | 'mul' | 'div' | 'dot'): Result<{ result: number[] | number, shape: number[] }, string> {
    if (a.length !== b.length) {
      return Err(`Dimensi tidak cocok: Tensor A (${a.length}) dan B (${b.length}) harus memiliki ukuran yang sama.`);
    }

    try {
      return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        let res: tf.Tensor;

        if (operation === 'dot') {
            res = tf.dot(tA, tB);
            return Ok({
                result: res.dataSync()[0],
                shape: []
            });
        }

        switch (operation) {
          case 'add': res = tf.add(tA, tB); break;
          case 'sub': res = tf.sub(tA, tB); break;
          case 'mul': res = tf.mul(tA, tB); break;
          case 'div': res = tf.div(tA, tB); break;
          default: return Err("Operasi tidak dikenal.");
        }

        return Ok({
          result: Array.from(res.dataSync()),
          shape: res.shape
        });
      });
    } catch (e) {
      return Err(`Gagal memanipulasi tensor: ${String(e)}`);
    }
  }

  /**
   * Menghitung kemiripan kosinus (Cosine Similarity) antara dua vektor.
   */
  static cosineSimilarity(a: number[], b: number[]): Result<{ similarity: number }, string> {
     if (a.length !== b.length) return Err("Vector dimensions must match for similarity check.");

     return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        const dotProduct = tf.dot(tA, tB);
        const normA = tf.norm(tA);
        const normB = tf.norm(tB);

        const similarity = tf.div(dotProduct, tf.mul(normA, normB));
        return Ok({ similarity: similarity.dataSync()[0] });
     });
  }

  static detectOutliers(data: number[], threshold: number = 2): Result<{ outliers: number[], indices: number[] }, string> {
      if (data.length === 0) return Err("Data kosong.");

      return tf.tidy(() => {
          const t = tf.tensor1d(data);
          const moments = tf.moments(t);
          const mean = moments.mean;
          const std = moments.variance.sqrt();

          const zScores = tf.abs(tf.div(tf.sub(t, mean), std));
          const mask = zScores.greater(threshold);

          const maskData = mask.dataSync();
          const outliers: number[] = [];
          const indices: number[] = [];

          maskData.forEach((isOutlier, index) => {
              if (isOutlier) {
                  outliers.push(data[index]);
                  indices.push(index);
              }
          });

          return Ok({ outliers, indices });
      });
  }

  static computeStatistics(data: number[]): Result<{ mean: number; std: number; min: number; max: number }, string> {
    if (data.length === 0) return Err("Empty dataset provided.");

    return tf.tidy(() => {
      const t = tf.tensor1d(data);
      const mean = t.mean().dataSync()[0];
      const std = tf.moments(t).variance.sqrt().dataSync()[0];
      const min = t.min().dataSync()[0];
      const max = t.max().dataSync()[0];

      return Ok({ mean, std, min, max });
    });
  }

  // --- ADVANCED MODEL MANAGEMENT ---

  static async loadModel(url: string): Promise<Result<{ message: string }, string>> {
      try {
          if (this.activeModel) this.activeModel.dispose();
          this.activeModel = await tf.loadLayersModel(url);
          return Ok({ message: `Model loaded successfully from ${url}` });
      } catch (e) {
          return Err(`Failed to load model: ${String(e)}`);
      }
  }

  /**
   * Creates a custom neural network architecture based on specifications.
   */
  static async createDenseModel(layersConfig: Array<{ units: number, activation?: string, inputShape?: number[] }>): Promise<Result<{ message: string }, string>> {
      try {
          if (this.activeModel) this.activeModel.dispose();

          const model = tf.sequential();

          layersConfig.forEach((config, index) => {
             const layerConfig: any = {
                 units: config.units,
                 activation: (config.activation as any) || 'relu'
             };
             // Add inputShape only to the first layer
             if (index === 0 && config.inputShape) {
                 layerConfig.inputShape = config.inputShape;
             }
             model.add(tf.layers.dense(layerConfig));
          });

          // Compile with standard optimizer for general tasks
          model.compile({ 
              loss: 'meanSquaredError', 
              optimizer: tf.train.adam(0.01) 
          });

          this.activeModel = model;
          return Ok({ message: `Custom Model Created: ${layersConfig.length} layers.` });
      } catch (e) {
          return Err(`Failed to create custom model: ${String(e)}`);
      }
  }

  /**
   * Trains the active model with provided data.
   */
  static async trainModel(x: number[], y: number[], epochs: number, learningRate: number = 0.01): Promise<Result<{ loss: number, epochs: number }, string>> {
     if (!this.activeModel) return Err("No model initialized. Call createDenseModel first.");

     try {
         // Re-compile if learning rate changed (simple approach)
         this.activeModel.compile({
             loss: 'meanSquaredError',
             optimizer: tf.train.adam(learningRate)
         });

         // Assuming 1D inputs/outputs for simplicity in this demo wrapper.
         // In a full app, we'd handle shapes dynamically.
         const inputShape = this.activeModel.inputs[0].shape;
         const inputDim = inputShape[inputShape.length - 1]; // e.g., null, 1 -> 1

         const numSamples = x.length / (inputDim || 1);

         const xs = tf.tensor(x, [numSamples, inputDim || 1]);
         const ys = tf.tensor(y, [numSamples, 1]); // Assuming single output for now

         const h = await this.activeModel.fit(xs, ys, { 
             epochs: epochs,
             shuffle: true,
             batchSize: 4 
         });

         xs.dispose();
         ys.dispose();

         const finalLoss = h.history.loss[h.history.loss.length - 1] as number;
         return Ok({ loss: finalLoss, epochs });
     } catch (e) {
         return Err(`Training failed: ${String(e)}`);
     }
  }

  static runPrediction(input: number[]): Result<{ prediction: number[] }, string> {
      if (!this.activeModel) return Err("No model loaded.");

      try {
          return tf.tidy(() => {
             const t = tf.tensor(input);
             // Auto-expand dims if it's a single sample without batch dim
             const inputTensor = t.shape.length === 1 ? t.expandDims(0) : t;

             const output = this.activeModel!.predict(inputTensor) as tf.Tensor;
             return Ok({ prediction: Array.from(output.dataSync()) });
          });
      } catch (e) {
          return Err(`Prediction failed: ${String(e)}`);
      }
  }

  // --- VECTOR DATABASE ---

  static async insertVector(text: string, vector: number[]): Promise<Result<{ id: string, total_records: number }, string>> {
    try {
      this.ensureDbLoaded();
      const id = Math.random().toString(36).substring(7);
      this.vectorDb.push({ id, text, vector });
      this.saveDb(); // Persist to local storage
      return Ok({ id, total_records: this.vectorDb.length });
    } catch (e) {
      return Err(`Failed to insert into vector DB: ${String(e)}`);
    }
  }

  static async searchVector(queryVector: number[], topK: number = 3): Promise<Result<{ matches: { text: string, score: number }[] }, string>> {
    this.ensureDbLoaded();
    if (this.vectorDb.length === 0) return Err("Vector Database is empty.");

    return tf.tidy(() => {
      const vectors = this.vectorDb.map(r => r.vector);
      const dbTensor = tf.tensor2d(vectors);
      const queryTensor = tf.tensor1d(queryVector);

      const dbNorm = tf.norm(dbTensor, 2, 1).expandDims(1);
      const queryNorm = tf.norm(queryTensor);

      const normalizedDb = tf.div(dbTensor, dbNorm);
      const normalizedQuery = tf.div(queryTensor, queryNorm);

      const scores = tf.matMul(normalizedDb, normalizedQuery.expandDims(1)).flatten();
      const k = Math.min(topK, this.vectorDb.length);
      const { values, indices } = tf.topk(scores, k);

      const topKIndices = indices.arraySync() as number[];
      const topKScores = values.arraySync() as number[];

      const matches = topKIndices.map((idx, i) => ({
        text: this.vectorDb[idx].text,
        score: topKScores[i]
      }));

      return Ok({ matches });
    });
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { tfStream, LogEntry } from './rx-engine';
import { TF_TOOLS } from './tools';

interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const MODELS = [
  { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro (Deep Research)' },
  { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash (Fast)' },
];

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Sentinel Core v5.0 initialized. \nArchitecture: Dynamic Neural Networks enabled. \nStrategy: Deep Chain-of-Thought.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState(MODELS[0].id);
  const [activeTab, setActiveTab] = useState<'chat' | 'logs'>('chat');
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const logScrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Auto-scroll chat
    if (activeTab === 'chat') {
        scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
    }
  }, [messages, activeTab]);

  useEffect(() => {
    // Auto-scroll logs
    if (activeTab === 'logs') {
        logScrollRef.current?.scrollTo(0, logScrollRef.current.scrollHeight);
    }
  }, [logs, activeTab]);

  // Subscribe to TF Stream Logs
  useEffect(() => {
      const sub = tfStream.logSubject.subscribe(entry => {
          setLogs(prev => [...prev, entry]);
      });
      return () => sub.unsubscribe();
  }, []);

  const getEmbedding = async (text: string): Promise<number[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const result = await ai.models.embedContent({
        model: 'gemini-embedding-001', // Updated to gemini-embedding-001 (3072 dimensions)
        contents: text
    });
    return result.embedding.values;
  };

  const handleToolCall = async (fc: any): Promise<any> => {
    let result;

    if (fc.name === 'performTensorMath') {
      result = await tfStream.dispatch({
        type: 'MATH',
        payload: fc.args
      });
    } else if (fc.name === 'cosineSimilarity') {
      result = await tfStream.dispatch({
        type: 'COSINE',
        payload: fc.args
      });
    } else if (fc.name === 'detectOutliers') {
      result = await tfStream.dispatch({
        type: 'OUTLIERS',
        payload: fc.args
      });
    } else if (fc.name === 'computeStatistics') {
      result = await tfStream.dispatch({
        type: 'STATS',
        payload: fc.args
      });
    } else if (fc.name === 'createDenseModel') {
        result = await tfStream.dispatch({
            type: 'CREATE_DENSE_MODEL',
            payload: { layers: fc.args.layers }
        });
    } else if (fc.name === 'trainModel') {
        result = await tfStream.dispatch({
            type: 'TRAIN_MODEL',
            payload: { 
                x: fc.args.x, 
                y: fc.args.y, 
                epochs: fc.args.epochs,
                learningRate: fc.args.learningRate 
            }
        });
    } else if (fc.name === 'runPrediction') {
        result = await tfStream.dispatch({
            type: 'PREDICT',
            payload: { input: fc.args.input }
        });
    } else if (fc.name === 'storeMemory') {
        try {
            const vector = await getEmbedding(fc.args.text);
            result = await tfStream.dispatch({
                type: 'DB_INSERT',
                payload: { text: fc.args.text, vector }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else if (fc.name === 'recallMemory') {
        try {
            const vector = await getEmbedding(fc.args.query);
            result = await tfStream.dispatch({
                type: 'DB_SEARCH',
                payload: { vector, topK: 3 }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else {
      return { error: "Unknown function" };
    }

    if (result.ok === false) {
      return { error: result.error };
    }
    return result.value;
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isPro = selectedModel.includes('pro');

      const response = await ai.models.generateContent({
        model: selectedModel,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
        })),
        config: {
          thinkingConfig: { thinkingBudget: isPro ? 32000 : 2048 }, 
          systemInstruction: `
You are Sentinel Core v5 (Deep Logic Edition).
You are an expert Machine Learning Engineer utilizing TensorFlow.js in a Reactive Stream.

**CORE DIRECTIVE**: 
The user PREFERS complexity and accuracy over speed. 
Do NOT simplify. Do NOT rush. Take your time to think deeply about the optimal solution.

**MEMORY & HISTORY**:
- You have access to a Vector Database via 'storeMemory' and 'recallMemory'.
- **CRITICAL**: If the user says "Simpan histori", "Save chat", "Remember this", or similar, you MUST:
  1. Summarize the important technical details and code from the current conversation.
  2. Call 'storeMemory' with this summary as the 'text' argument.
  3. Confirm to the user that the memory has been secured.
- Always check 'recallMemory' when the user refers to past projects or "last time".

**ADVANCED CAPABILITIES**:
1.  **Custom Neural Networks**: 
    - You can build custom architectures using 'createDenseModel'.
    - If a user asks for non-linear problems (e.g., XOR, Sine Wave, Complex patterns), DO NOT use simple regression.
    - Build Multi-Layer Perceptrons (MLP). Example: Input -> Dense(16, relu) -> Dense(8, relu) -> Output.
2.  **Iterative Training**:
    - Use 'trainModel' to fit data. 
    - Recommend higher epochs (e.g., 100-500) for complex data to ensure convergence.
3.  **Data Science Pipeline**:
    - Always 'computeStatistics' and 'detectOutliers' BEFORE training a model on raw data.
    - If you find outliers, filter them out before training.

**EXAMPLE WORKFLOW (Deep Thinking)**:
User: "Train a model to learn the XOR function."
Your Plan:
1.  Analyze: XOR is non-linear. Linear regression will fail.
2.  Design: Need at least one hidden layer.
3.  Action: createDenseModel([{units: 4, activation: 'sigmoid', inputShape: [2]}, {units: 1, activation: 'sigmoid'}])
4.  Action: trainModel(x=[0,0, 0,1, 1,0, 1,1], y=[0, 1, 1, 0], epochs=500)
5.  Verify: runPrediction([0,1]) -> Expect ~0.99.
          `,
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

      const candidate = response.candidates[0];

      if (candidate.content.parts.some(p => p.functionCall)) {
          const functionCalls = candidate.content.parts.filter(p => p.functionCall).map(p => p.functionCall);

          // Removed intermediate "Deep Thinking" message to avoid clutter

          const toolResponses = await Promise.all(functionCalls.map(async (fc) => {
            const result = await handleToolCall(fc);
            return { functionResponse: { name: fc.name, response: result } };
          }));

          const finalResponse = await ai.models.generateContent({
            model: selectedModel,
            contents: [
                ...messages.map(m => ({ role: m.role === 'system' ? 'user' : (m.role as any), parts: [{ text: m.content }] })),
                { role: 'user', parts: [{ text: userMsg.content }] },
                { role: 'model', parts: candidate.content.parts },
                { role: 'user', parts: toolResponses as any }
            ],
            config: { 
                thinkingConfig: { thinkingBudget: isPro ? 10000 : 1024 }, 
                tools: [{ functionDeclarations: TF_TOOLS as any }] 
            }
          });

          setMessages(prev => [...prev, { role: 'model', content: finalResponse.text || "Operations complete." }]);
      } else {
