import * as tf from '@tensorflow/tfjs';
import { Result, Ok, Err } from './types';

interface VectorRecord {
  id: string;
  text: string;
  vector: number[];
}

/**
 * TF.JS SERVICE (THE ENGINE)
 * Handles all tensor manipulations and mathematical computations.
 */
export class TensorFlowEngine {
  // Store the currently loaded model in memory
  private static activeModel: tf.LayersModel | null = null;
  // In-Memory Vector Database (Simulating LanceDB)
  private static vectorDb: VectorRecord[] = [];
  private static dbLoaded: boolean = false;
  private static DB_KEY = 'SENTINEL_VECTOR_DB_V1';

  private static ensureDbLoaded() {
      if (!this.dbLoaded && typeof window !== 'undefined') {
          try {
              const saved = localStorage.getItem(this.DB_KEY);
              if (saved) {
                  this.vectorDb = JSON.parse(saved);
                  console.log(`[Engine] Loaded ${this.vectorDb.length} memories from storage.`);
              }
          } catch (e) {
              console.error("[Engine] Failed to load DB", e);
          }
          this.dbLoaded = true;
      }
  }

  private static saveDb() {
      if (typeof window !== 'undefined') {
          try {
              // Limit check: Simple safeguard for LocalStorage (5MB limit)
              // If too large, keep only the last 50 items
              if (this.vectorDb.length > 50) {
                  this.vectorDb = this.vectorDb.slice(-50);
              }
              localStorage.setItem(this.DB_KEY, JSON.stringify(this.vectorDb));
          } catch (e) {
              console.error("[Engine] Failed to save DB", e);
          }
      }
  }

  /**
   * Melakukan operasi matematika element-wise pada dua tensor.
   */
  static performTensorMath(a: number[], b: number[], operation: 'add' | 'sub' | 'mul' | 'div' | 'dot'): Result<{ result: number[] | number, shape: number[] }, string> {
    if (a.length !== b.length) {
      return Err(`Dimensi tidak cocok: Tensor A (${a.length}) dan B (${b.length}) harus memiliki ukuran yang sama.`);
    }

    try {
      return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        let res: tf.Tensor;

        if (operation === 'dot') {
            res = tf.dot(tA, tB);
            return Ok({
                result: res.dataSync()[0],
                shape: []
            });
        }

        switch (operation) {
          case 'add': res = tf.add(tA, tB); break;
          case 'sub': res = tf.sub(tA, tB); break;
          case 'mul': res = tf.mul(tA, tB); break;
          case 'div': res = tf.div(tA, tB); break;
          default: return Err("Operasi tidak dikenal.");
        }

        return Ok({
          result: Array.from(res.dataSync()),
          shape: res.shape
        });
      });
    } catch (e) {
      return Err(`Gagal memanipulasi tensor: ${String(e)}`);
    }
  }

  /**
   * Menghitung kemiripan kosinus (Cosine Similarity) antara dua vektor.
   */
  static cosineSimilarity(a: number[], b: number[]): Result<{ similarity: number }, string> {
     if (a.length !== b.length) return Err("Vector dimensions must match for similarity check.");

     return tf.tidy(() => {
        const tA = tf.tensor1d(a);
        const tB = tf.tensor1d(b);
        const dotProduct = tf.dot(tA, tB);
        const normA = tf.norm(tA);
        const normB = tf.norm(tB);

        const similarity = tf.div(dotProduct, tf.mul(normA, normB));
        return Ok({ similarity: similarity.dataSync()[0] });
     });
  }

  static detectOutliers(data: number[], threshold: number = 2): Result<{ outliers: number[], indices: number[] }, string> {
      if (data.length === 0) return Err("Data kosong.");

      return tf.tidy(() => {
          const t = tf.tensor1d(data);
          const moments = tf.moments(t);
          const mean = moments.mean;
          const std = moments.variance.sqrt();

          const zScores = tf.abs(tf.div(tf.sub(t, mean), std));
          const mask = zScores.greater(threshold);

          const maskData = mask.dataSync();
          const outliers: number[] = [];
          const indices: number[] = [];

          maskData.forEach((isOutlier, index) => {
              if (isOutlier) {
                  outliers.push(data[index]);
                  indices.push(index);
              }
          });

          return Ok({ outliers, indices });
      });
  }

  static computeStatistics(data: number[]): Result<{ mean: number; std: number; min: number; max: number }, string> {
    if (data.length === 0) return Err("Empty dataset provided.");

    return tf.tidy(() => {
      const t = tf.tensor1d(data);
      const mean = t.mean().dataSync()[0];
      const std = tf.moments(t).variance.sqrt().dataSync()[0];
      const min = t.min().dataSync()[0];
      const max = t.max().dataSync()[0];

      return Ok({ mean, std, min, max });
    });
  }

  // --- ADVANCED MODEL MANAGEMENT ---

  static async loadModel(url: string): Promise<Result<{ message: string }, string>> {
      try {
          if (this.activeModel) this.activeModel.dispose();
          this.activeModel = await tf.loadLayersModel(url);
          return Ok({ message: `Model loaded successfully from ${url}` });
      } catch (e) {
          return Err(`Failed to load model: ${String(e)}`);
      }
  }

  static async saveModelLocal(name: string): Promise<Result<{ message: string; path: string }, string>> {
      if (!this.activeModel) return Err("No active model to save. Create or train one first.");
      try {
          const savePath = `localstorage://${name}`;
          await this.activeModel.save(savePath);
          return Ok({ message: `Model saved successfully.`, path: savePath });
      } catch (e) {
          return Err(`Failed to save model: ${String(e)}`);
      }
  }

  static async loadLocalModel(name: string): Promise<Result<{ message: string }, string>> {
      try {
          const loadPath = `localstorage://${name}`;
          if (this.activeModel) this.activeModel.dispose();
          this.activeModel = await tf.loadLayersModel(loadPath);
          return Ok({ message: `Model '${name}' loaded from LocalStorage.` });
      } catch (e) {
          return Err(`Failed to load model '${name}': ${String(e)} (Model might not exist)`);
      }
  }

  static async listLocalModels(): Promise<Result<{ models: any }, string>> {
      try {
          const models = await tf.io.listModels();
          return Ok({ models });
      } catch (e) {
          return Err(`Failed to list models: ${String(e)}`);
      }
  }

  /**
   * Creates a custom neural network architecture based on specifications.
   */
  static async createDenseModel(layersConfig: Array<{ units: number, activation?: string, inputShape?: number[] }>): Promise<Result<{ message: string }, string>> {
      try {
          if (this.activeModel) this.activeModel.dispose();

          const model = tf.sequential();

          layersConfig.forEach((config, index) => {
             const layerConfig: any = {
                 units: config.units,
                 activation: (config.activation as any) || 'relu'
             };
             // Add inputShape only to the first layer
             if (index === 0 && config.inputShape) {
                 layerConfig.inputShape = config.inputShape;
             }
             model.add(tf.layers.dense(layerConfig));
          });

          // Compile with standard optimizer for general tasks
          model.compile({ 
              loss: 'meanSquaredError', 
              optimizer: tf.train.adam(0.01) 
          });

          this.activeModel = model;
          return Ok({ message: `Custom Model Created: ${layersConfig.length} layers.` });
      } catch (e) {
          return Err(`Failed to create custom model: ${String(e)}`);
      }
  }

  /**
   * Trains the active model with provided data.
   */
  static async trainModel(x: number[], y: number[], epochs: number, learningRate: number = 0.01): Promise<Result<{ loss: number, epochs: number }, string>> {
     if (!this.activeModel) return Err("No model initialized. Call createDenseModel first.");

     try {
         // Re-compile if learning rate changed
         this.activeModel.compile({
             loss: 'meanSquaredError',
             optimizer: tf.train.adam(learningRate)
         });

         const xTensor = tf.tensor(x);
         const yTensor = tf.tensor(y);

         // Dynamic reshape based on model input/output shapes
         const inputShape = this.activeModel.inputs[0].shape;
         const nFeatures = inputShape[1];

         if (!nFeatures) return Err("Model input shape undefined.");

         const numSamples = x.length / nFeatures;
         const reshapedX = xTensor.reshape([numSamples, nFeatures]);

         const outputShape = this.activeModel.outputs[0].shape;
         const nOutputs = outputShape[1] || 1;
         const reshapedY = yTensor.reshape([numSamples, nOutputs]);

         const h = await this.activeModel.fit(reshapedX, reshapedY, {
             epochs: epochs,
             shuffle: true,
             verbose: 0
         });

         xTensor.dispose();
         yTensor.dispose();
         reshapedX.dispose();
         reshapedY.dispose();

         const finalLoss = h.history.loss[h.history.loss.length - 1] as number;
         return Ok({ loss: finalLoss, epochs });

     } catch (e) {
         return Err(`Training failed: ${String(e)}`);
     }
  }

  /**
   * Runs inference on the active model.
   */
  static async runPrediction(input: number[]): Promise<Result<{ prediction: number[] }, string>> {
      if (!this.activeModel) return Err("No model loaded. Train or load a model first.");
      try {
          const inputShape = this.activeModel.inputs[0].shape;
          const nFeatures = inputShape[1];
          if (!nFeatures) return Err("Model input shape undefined.");

          const t = tf.tensor(input, [1, nFeatures]);
          const pred = this.activeModel.predict(t) as tf.Tensor;
          const result = Array.from(pred.dataSync());

          t.dispose();
          pred.dispose();

          return Ok({ prediction: result });
      } catch (e) {
          return Err(`Prediction failed: ${String(e)}`);
      }
  }

  /**
   * Stores a vector memory.
   */
  static async insertVector(text: string, vector: number[]): Promise<Result<{ id: string }, string>> {
      this.ensureDbLoaded();
      const id = Math.random().toString(36).substring(2, 10);
      this.vectorDb.push({ id, text, vector });
      this.saveDb();
      return Ok({ id });
  }

  /**
   * Searches for similar vectors using cosine similarity.
   */
  static async searchVector(vector: number[], topK: number = 3): Promise<Result<{ matches: any[] }, string>> {
      this.ensureDbLoaded();
      if (this.vectorDb.length === 0) return Err("Memory DB is empty.");

      // Compute cosine similarity for all
      const matches = this.vectorDb.map(record => {
          const sim = tf.tidy(() => {
              const a = tf.tensor1d(vector);
              const b = tf.tensor1d(record.vector);
              return tf.div(tf.dot(a, b), tf.mul(tf.norm(a), tf.norm(b))).dataSync()[0];
          });
          return { ...record, score: sim };
      });

      // Sort descending
      matches.sort((a, b) => b.score - a.score);
      return Ok({ matches: matches.slice(0, topK) });
  }
}

import { Subject, firstValueFrom, from, of } from 'rxjs';
import { filter, map, mergeMap, catchError, tap, share } from 'rxjs';
import { TensorFlowEngine } from './engine';
import { TFAction, Result, Err } from './types';

// Unique ID generator for stream correlation
const uuid = () => Math.random().toString(36).substring(2, 9);

interface StreamPacket {
  id: string;
  action: TFAction;
}

export interface LogEntry {
  id: string;
  timestamp: number;
  type: 'ACTION' | 'RESULT' | 'ERROR';
  actionType?: string;
  message: string;
  data?: any;
}

class RxTensorFlowBridge {
  private _actionSubject = new Subject<StreamPacket>();
  public readonly logSubject = new Subject<LogEntry>();

  public readonly resultStream$ = this._actionSubject.pipe(
    // Log Action Dispatch
    tap(packet => {
      this.logSubject.next({
        id: packet.id,
        timestamp: Date.now(),
        type: 'ACTION',
        actionType: packet.action.type,
        message: `Dispatching ${packet.action.type}`,
        data: packet.action.payload
      });
      console.log(`[RxJS] Processing Action: ${packet.action.type}`, packet);
    }),
    mergeMap(packet => {
      return from(this._execute(packet.action)).pipe(
        // Pass actionType through the pipe for the next logger
        map(result => ({ id: packet.id, result, actionType: packet.action.type })),
        catchError(err => of({ 
          id: packet.id, 
          result: Err(`Stream Error: ${String(err)}`),
          actionType: packet.action.type
        }))
      );
    }),
    // Log Result/Error
    tap(packet => {
       this.logSubject.next({
         id: packet.id,
         timestamp: Date.now(),
         type: packet.result.ok ? 'RESULT' : 'ERROR',
         actionType: packet.actionType,
         message: packet.result.ok ? `Success: ${packet.actionType}` : `Failed: ${packet.actionType}`,
         data: packet.result.ok ? packet.result.value : packet.result.error
       });
    }),
    share()
  );

  constructor() {
    this.resultStream$.subscribe(); 
  }

  public async dispatch(action: TFAction): Promise<Result<any, string>> {
    const id = uuid();
    const resultPromise = firstValueFrom(
      this.resultStream$.pipe(
        filter(packet => packet.id === id),
        map(packet => packet.result)
      )
    );
    this._actionSubject.next({ id, action });
    return resultPromise;
  }

  private async _execute(action: TFAction): Promise<Result<any, string>> {
    switch (action.type) {
      case 'MATH':
        return TensorFlowEngine.performTensorMath(action.payload.arrayA, action.payload.arrayB, action.payload.operation);
      case 'COSINE':
        return TensorFlowEngine.cosineSimilarity(action.payload.vectorA, action.payload.vectorB);
      case 'OUTLIERS':
        return TensorFlowEngine.detectOutliers(action.payload.data, action.payload.threshold);
      case 'STATS':
        return TensorFlowEngine.computeStatistics(action.payload.data);
      case 'LOAD_MODEL':
        return TensorFlowEngine.loadModel(action.payload.url);
      case 'CREATE_DENSE_MODEL':
        return TensorFlowEngine.createDenseModel(action.payload.layers);
      case 'TRAIN_MODEL':
        return TensorFlowEngine.trainModel(action.payload.x, action.payload.y, action.payload.epochs, action.payload.learningRate);
      case 'PREDICT':
        return TensorFlowEngine.runPrediction(action.payload.input);
      case 'DB_INSERT':
        return TensorFlowEngine.insertVector(action.payload.text, action.payload.vector);
      case 'DB_SEARCH':
        return TensorFlowEngine.searchVector(action.payload.vector, action.payload.topK);
      case 'SAVE_MODEL_LOCAL':
        return TensorFlowEngine.saveModelLocal(action.payload.name);
      case 'LOAD_MODEL_LOCAL':
        return TensorFlowEngine.loadLocalModel(action.payload.name);
      case 'LIST_MODELS_LOCAL':
        return TensorFlowEngine.listLocalModels();
      default:
        return Err("Unknown Action Type in Stream");
    }
  }
}

export const tfStream = new RxTensorFlowBridge();

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { tfStream, LogEntry } from './rx-engine';
import { TF_TOOLS } from './tools';

interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const MODELS = [
  { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro (Deep Research)' },
  { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash (Fast)' },
  { id: 'gemini-2.5-flash', name: 'Gemini 2.5 Flash' },
];

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Sentinel Core v5.0 initialized. \nArchitecture: Dynamic Neural Networks enabled. \nStrategy: Deep Chain-of-Thought.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState(MODELS[0].id);
  const [activeTab, setActiveTab] = useState<'chat' | 'logs'>('chat');
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const logScrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Auto-scroll chat
    if (activeTab === 'chat') {
        scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
    }
  }, [messages, activeTab]);

  useEffect(() => {
    // Auto-scroll logs
    if (activeTab === 'logs') {
        logScrollRef.current?.scrollTo(0, logScrollRef.current.scrollHeight);
    }
  }, [logs, activeTab]);

  // Subscribe to TF Stream Logs
  useEffect(() => {
      const sub = tfStream.logSubject.subscribe(entry => {
          setLogs(prev => [...prev, entry]);
      });
      return () => sub.unsubscribe();
  }, []);

  const getEmbedding = async (text: string): Promise<number[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const result = await ai.models.embedContent({
        model: 'gemini-embedding-001', // Updated to gemini-embedding-001 (3072 dimensions)
        contents: text
    });
    // Check if embedding exists
    if (!result.embedding || !result.embedding.values) {
        throw new Error("Failed to generate embedding");
    }
    return result.embedding.values;
  };

  const handleToolCall = async (fc: any): Promise<any> => {
    let result;

    if (fc.name === 'performTensorMath') {
      result = await tfStream.dispatch({
        type: 'MATH',
        payload: fc.args
      });
    } else if (fc.name === 'cosineSimilarity') {
      result = await tfStream.dispatch({
        type: 'COSINE',
        payload: fc.args
      });
    } else if (fc.name === 'detectOutliers') {
      result = await tfStream.dispatch({
        type: 'OUTLIERS',
        payload: fc.args
      });
    } else if (fc.name === 'computeStatistics') {
      result = await tfStream.dispatch({
        type: 'STATS',
        payload: fc.args
      });
    } else if (fc.name === 'createDenseModel') {
        result = await tfStream.dispatch({
            type: 'CREATE_DENSE_MODEL',
            payload: { layers: fc.args.layers }
        });
    } else if (fc.name === 'trainModel') {
        result = await tfStream.dispatch({
            type: 'TRAIN_MODEL',
            payload: { 
                x: fc.args.x, 
                y: fc.args.y, 
                epochs: fc.args.epochs,
                learningRate: fc.args.learningRate 
            }
        });
    } else if (fc.name === 'runPrediction') {
        result = await tfStream.dispatch({
            type: 'PREDICT',
            payload: { input: fc.args.input }
        });
    } else if (fc.name === 'storeMemory') {
        try {
            const vector = await getEmbedding(fc.args.text);
            result = await tfStream.dispatch({
                type: 'DB_INSERT',
                payload: { text: fc.args.text, vector }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else if (fc.name === 'recallMemory') {
        try {
            const vector = await getEmbedding(fc.args.query);
            result = await tfStream.dispatch({
                type: 'DB_SEARCH',
                payload: { vector, topK: 3 }
            });
        } catch (e) {
            return { error: `Embedding failed: ${e}` };
        }
    } else if (fc.name === 'saveModel') {
        result = await tfStream.dispatch({
            type: 'SAVE_MODEL_LOCAL',
            payload: { name: fc.args.name }
        });
    } else if (fc.name === 'loadLocalModel') {
        result = await tfStream.dispatch({
            type: 'LOAD_MODEL_LOCAL',
            payload: { name: fc.args.name }
        });
    } else if (fc.name === 'listLocalModels') {
        result = await tfStream.dispatch({
            type: 'LIST_MODELS_LOCAL',
            payload: {}
        });
    } else {
      return { error: "Unknown function" };
    }

    if (result.ok === false) {
      return { error: result.error };
    }
    return result.value;
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isPro = selectedModel.includes('pro');

      const response = await ai.models.generateContent({
        model: selectedModel,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
        })),
        config: {
          thinkingConfig: { thinkingBudget: isPro ? 32000 : 2048 }, 
          systemInstruction: `
You are Sentinel Core v5 (Deep Logic Edition).
You are an expert Machine Learning Engineer utilizing TensorFlow.js in a Reactive Stream.

**CORE DIRECTIVE**: 
The user PREFERS complexity and accuracy over speed. 
Do NOT simplify. Do NOT rush. Take your time to think deeply about the optimal solution.

**MEMORY & HISTORY**:
- You have access to a Vector Database via 'storeMemory' and 'recallMemory'.
- **CRITICAL**: If the user says "Simpan histori", "Save chat", "Remember this", or similar, you MUST:
  1. Summarize the important technical details and code from the current conversation.
  2. Call 'storeMemory' with this summary as the 'text' argument.
  3. Confirm to the user that the memory has been secured.
- Always check 'recallMemory' when the user refers to past projects or "last time".

**MODEL PERSISTENCE**:
- After training a model ('trainModel'), ALWAYS offer to save it using 'saveModel' (e.g., saveModel({name: 'my_model'})).
- If the user wants to reuse a previous model, use 'listLocalModels' to find it and 'loadLocalModel' to restore it.

**ADVANCED CAPABILITIES**:
1.  **Custom Neural Networks**: 
    - You can build custom architectures using 'createDenseModel'.
    - If a user asks for non-linear problems (e.g., XOR, Sine Wave, Complex patterns), DO NOT use simple regression.
    - Build Multi-Layer Perceptrons (MLP). Example: Input -> Dense(16, relu) -> Dense(8, relu) -> Output.
2.  **Iterative Training**:
    - Use 'trainModel' to fit data. 
    - Recommend higher epochs (e.g., 100-500) for complex data to ensure convergence.
3.  **Data Science Pipeline**:
    - Always 'computeStatistics' and 'detectOutliers' BEFORE training a model on raw data.
    - If you find outliers, filter them out before training.

**EXAMPLE WORKFLOW (Deep Thinking)**:
User: "Train a model to learn the XOR function."
Your Plan:
1.  Analyze: XOR is non-linear. Linear regression will fail.
2.  Design: Need at least one hidden layer.
3.  Action: createDenseModel([{units: 4, activation: 'sigmoid', inputShape: [2]}, {units: 1, activation: 'sigmoid'}])
4.  Action: trainModel(x=[0,0, 0,1, 1,0, 1,1], y=[0, 1, 1, 0], epochs=500)
5.  Verify: runPrediction([0,1]) -> Expect ~0.99.
6.  Offer: "Shall I save this model as 'xor_v1'?"
          `,
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

      const candidate = response.candidates?.[0];

      // SAFETY CHECK: Ensure candidate and content exist
      if (!candidate || !candidate.content || !candidate.content.parts) {
          console.warn("Empty response or safety block triggered:", candidate);
          setMessages(prev => [...prev, { 
              role: 'system', 
              content: `System Alert: The model returned no content. \nReason: ${candidate?.finishReason || 'Unknown (Possible Safety Filter)'}` 
          }]);
          return;
      }

      if (candidate.content.parts.some(p => p.functionCall)) {
          const functionCalls = candidate.content.parts.filter(p => p.functionCall).map(p => p.functionCall);

          const toolResponses = await Promise.all(functionCalls.map(async (fc) => {
            const result = await handleToolCall(fc);
            return { functionResponse: { name: fc.name, response: result } };
          }));

          const finalResponse = await ai.models.generateContent({
            model: selectedModel,
            contents: [
                ...messages.map(m => ({ role: m.role === 'system' ? 'user' : (m.role as any), parts: [{ text: m.content }] })),
                { role: 'user', parts: [{ text: userMsg.content }] },
                { role: 'model', parts: candidate.content.parts },
                { role: 'user', parts: toolResponses as any }
            ],
            config: { 
                thinkingConfig: { thinkingBudget: isPro ? 10000 : 1024 }, 
                tools: [{ functionDeclarations: TF_TOOLS as any }] 
            }
          });

          setMessages(prev => [...prev, { role: 'model', content: finalResponse.text || "Operations complete." }]);
      } else {
          setMessages(prev => [...prev, { role: 'model', content: response.text || "Process completed." }]);
      }

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'system', content: `CRITICAL ERROR: ${String(error)}` }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-[#020617] p-4 md:p-8">
      <header className="flex flex-col gap-4 mb-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-indigo-500/20 flex items-center justify-center border border-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                  <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                  </svg>
              </div>
              <div>
                  <h1 className="text-xl font-bold tracking-tight glow-text uppercase">Sentinel Core v5.0</h1>
                  <div className="flex items-center gap-2 mt-0.5">
                    <span className="text-[10px] text-slate-500 mono">MODE:</span>
                    <select 
                      value={selectedModel}
                      onChange={(e) => setSelectedModel(e.target.value)}
                      className="bg-transparent text-[10px] font-bold text-indigo-400 border-none outline-none cursor-pointer hover:text-indigo-300 uppercase tracking-widest p-0 m-0"
                    >
                      {MODELS.map(m => (
                        <option key={m.id} value={m.id} className="bg-[#0f172a] text-slate-300">
                          {m.name}
                        </option>
                      ))}
                    </select>
                  </div>
              </div>
          </div>
          <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full animate-pulse ${selectedModel.includes('flash') ? 'bg-amber-500' : 'bg-rose-500'}`}></div>
              <span className={`text-xs mono uppercase tracking-widest ${selectedModel.includes('flash') ? 'text-amber-500' : 'text-rose-500'}`}>
                {selectedModel.includes('flash') ? 'Fast' : 'MAX REASONING'}
              </span>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex gap-1 bg-slate-900/50 p-1 rounded-lg w-fit border border-slate-800">
            <button 
                onClick={() => setActiveTab('chat')}
