import { Subject, firstValueFrom, from, of } from 'rxjs';
import { filter, map, mergeMap, catchError, tap, share } from 'rxjs';
import { TensorFlowEngine } from './engine';
import { TFAction, Result, Err } from './types';

// Unique ID generator for stream correlation
const uuid = () => Math.random().toString(36).substring(2, 9);

interface StreamPacket {
  id: string;
  action: TFAction;
}

export interface LogEntry {
  id: string;
  timestamp: number;
  type: 'ACTION' | 'RESULT' | 'ERROR';
  actionType?: string;
  message: string;
  data?: any;
}

class RxTensorFlowBridge {
  private _actionSubject = new Subject<StreamPacket>();
  public readonly logSubject = new Subject<LogEntry>();

  public readonly resultStream$ = this._actionSubject.pipe(
    // Log Action Dispatch
    tap(packet => {
      this.logSubject.next({
        id: packet.id,
        timestamp: Date.now(),
        type: 'ACTION',
        actionType: packet.action.type,
        message: `Dispatching ${packet.action.type}`,
        data: packet.action.payload
      });
      console.log(`[RxJS] Processing Action: ${packet.action.type}`, packet);
    }),
    mergeMap(packet => {
      return from(this._execute(packet.action)).pipe(
        // Pass actionType through the pipe for the next logger
        map(result => ({ id: packet.id, result, actionType: packet.action.type })),
        catchError(err => of({ 
          id: packet.id, 
          result: Err(`Stream Error: ${String(err)}`),
          actionType: packet.action.type
        }))
      );
    }),
    // Log Result/Error
    tap(packet => {
       this.logSubject.next({
         id: packet.id,
         timestamp: Date.now(),
         type: packet.result.ok ? 'RESULT' : 'ERROR',
         actionType: packet.actionType,
         message: packet.result.ok ? `Success: ${packet.actionType}` : `Failed: ${packet.actionType}`,
         data: packet.result.ok ? packet.result.value : packet.result.error
       });
    }),
    share()
  );

  constructor() {
    this.resultStream$.subscribe(); 
  }

  public async dispatch(action: TFAction): Promise<Result<any, string>> {
    const id = uuid();
    const resultPromise = firstValueFrom(
      this.resultStream$.pipe(
        filter(packet => packet.id === id),
        map(packet => packet.result)
      )
    );
    this._actionSubject.next({ id, action });
    return resultPromise;
  }

  private async _execute(action: TFAction): Promise<Result<any, string>> {
    switch (action.type) {
      case 'MATH':
        return TensorFlowEngine.performTensorMath(action.payload.arrayA, action.payload.arrayB, action.payload.operation);
      case 'COSINE':
        return TensorFlowEngine.cosineSimilarity(action.payload.vectorA, action.payload.vectorB);
      case 'OUTLIERS':
        return TensorFlowEngine.detectOutliers(action.payload.data, action.payload.threshold);
      case 'STATS':
        return TensorFlowEngine.computeStatistics(action.payload.data);
      case 'LOAD_MODEL':
        return TensorFlowEngine.loadModel(action.payload.url);
      case 'CREATE_DENSE_MODEL':
        return TensorFlowEngine.createDenseModel(action.payload.layers);
      case 'TRAIN_MODEL':
        return TensorFlowEngine.trainModel(action.payload.x, action.payload.y, action.payload.epochs, action.payload.learningRate);
      case 'PREDICT':
        return TensorFlowEngine.runPrediction(action.payload.input);
      case 'DB_INSERT':
        return TensorFlowEngine.insertVector(action.payload.text, action.payload.vector);
      case 'DB_SEARCH':
        return TensorFlowEngine.searchVector(action.payload.vector, action.payload.topK);
      case 'SAVE_MODEL_LOCAL':
        return TensorFlowEngine.saveModelLocal(action.payload.name);
      case 'LOAD_MODEL_LOCAL':
        return TensorFlowEngine.loadLocalModel(action.payload.name);
      case 'LIST_MODELS_LOCAL':
        return TensorFlowEngine.listLocalModels();
      default:
        return Err("Unknown Action Type in Stream");
    }
  }
}

export const tfStream = new RxTensorFlowBridge();

import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import { GoogleGenAI } from '@google/genai';
import { tfStream, LogEntry } from './rx-engine';
import { TF_TOOLS } from './tools';

interface Message {
  role: 'user' | 'model' | 'system';
  content: string;
  isToolCall?: boolean;
}

const MODELS = [
  { id: 'gemini-3-pro-preview', name: 'Gemini 3 Pro (Deep Research)' },
  { id: 'gemini-3-flash-preview', name: 'Gemini 3 Flash (Fast)' },
  { id: 'gemini-2.5-flash', name: 'Gemini 2.5 Flash' },
  { id: 'gemini-flash-latest', name: 'Gemini Flash (Stable)' },
];

const App = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'system', content: 'Sentinel Core v5.0 initialized. \nArchitecture: Dynamic Neural Networks enabled. \nStrategy: Deep Chain-of-Thought.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState(MODELS[0].id);
  const [activeTab, setActiveTab] = useState<'chat' | 'logs'>('chat');
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const scrollRef = useRef<HTMLDivElement>(null);
  const logScrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Auto-scroll chat
    if (activeTab === 'chat') {
        scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
    }
  }, [messages, activeTab]);

  useEffect(() => {
    // Auto-scroll logs
    if (activeTab === 'logs') {
        logScrollRef.current?.scrollTo(0, logScrollRef.current.scrollHeight);
    }
  }, [logs, activeTab]);

  // Subscribe to TF Stream Logs
  useEffect(() => {
      const sub = tfStream.logSubject.subscribe(entry => {
          setLogs(prev => [...prev, entry]);
      });
      return () => sub.unsubscribe();
  }, []);

  const getEmbedding = async (text: string): Promise<number[]> => {
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const result = await ai.models.embedContent({
            model: 'text-embedding-004',
            contents: text
        });
        // Check if embedding exists
        if (!result.embedding || !result.embedding.values) {
            throw new Error("Failed to generate embedding");
        }
        return result.embedding.values;
    } catch (e: any) {
        console.warn("Embedding generation failed:", e);
        if (e.status === 403 || e.message?.includes('403')) {
            throw new Error("Embedding Permission Denied (403). Check API Key.");
        }
        if (e.status === 429 || e.message?.includes('429')) {
            throw new Error("Embedding Quota Exceeded (429).");
        }
        throw e;
    }
  };

  const handleToolCall = async (fc: any): Promise<any> => {
    let result;

    if (fc.name === 'performTensorMath') {
      result = await tfStream.dispatch({
        type: 'MATH',
        payload: fc.args
      });
    } else if (fc.name === 'cosineSimilarity') {
      result = await tfStream.dispatch({
        type: 'COSINE',
        payload: fc.args
      });
    } else if (fc.name === 'detectOutliers') {
      result = await tfStream.dispatch({
        type: 'OUTLIERS',
        payload: fc.args
      });
    } else if (fc.name === 'computeStatistics') {
      result = await tfStream.dispatch({
        type: 'STATS',
        payload: fc.args
      });
    } else if (fc.name === 'createDenseModel') {
        result = await tfStream.dispatch({
            type: 'CREATE_DENSE_MODEL',
            payload: { layers: fc.args.layers }
        });
    } else if (fc.name === 'trainModel') {
        result = await tfStream.dispatch({
            type: 'TRAIN_MODEL',
            payload: { 
                x: fc.args.x, 
                y: fc.args.y, 
                epochs: fc.args.epochs,
                learningRate: fc.args.learningRate 
            }
        });
    } else if (fc.name === 'runPrediction') {
        result = await tfStream.dispatch({
            type: 'PREDICT',
            payload: { input: fc.args.input }
        });
    } else if (fc.name === 'storeMemory') {
        try {
            const vector = await getEmbedding(fc.args.text);
            result = await tfStream.dispatch({
                type: 'DB_INSERT',
                payload: { text: fc.args.text, vector }
            });
        } catch (e: any) {
            return { error: `Memory Store Failed: ${e.message}` };
        }
    } else if (fc.name === 'recallMemory') {
        try {
            const vector = await getEmbedding(fc.args.query);
            result = await tfStream.dispatch({
                type: 'DB_SEARCH',
                payload: { vector, topK: 3 }
            });
        } catch (e: any) {
             return { error: `Memory Recall Failed: ${e.message}` };
        }
    } else if (fc.name === 'saveModel') {
        result = await tfStream.dispatch({
            type: 'SAVE_MODEL_LOCAL',
            payload: { name: fc.args.name }
        });
    } else if (fc.name === 'loadLocalModel') {
        result = await tfStream.dispatch({
            type: 'LOAD_MODEL_LOCAL',
            payload: { name: fc.args.name }
        });
    } else if (fc.name === 'listLocalModels') {
        result = await tfStream.dispatch({
            type: 'LIST_MODELS_LOCAL',
            payload: {}
        });
    } else {
      return { error: "Unknown function" };
    }

    if (result.ok === false) {
      return { error: result.error };
    }
    return result.value;
  };

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const isPro = selectedModel.includes('pro');
      const isFlash = selectedModel.includes('flash');

      const response = await ai.models.generateContent({
        model: selectedModel,
        contents: [...messages, userMsg].map(m => ({
            role: m.role === 'system' ? 'user' : (m.role as any),
            parts: [{ text: m.content }]
        })),
        config: {
          thinkingConfig: (isPro || selectedModel.includes('2.5')) ? { thinkingBudget: isPro ? 16000 : 2048 } : undefined, 
          systemInstruction: `
You are Sentinel Core v5 (Deep Logic Edition).
You are an expert Machine Learning Engineer utilizing TensorFlow.js.

**CORE DIRECTIVE**: 
The user PREFERS complexity and accuracy over speed. 
Do NOT simplify. Do NOT rush. Take your time to think deeply about the optimal solution.

**MEMORY & HISTORY**:
- You have access to a Vector Database via 'storeMemory' and 'recallMemory'.
- **CRITICAL**: If the user says "Simpan histori", "Save chat", "Remember this", or similar, you MUST:
  1. Summarize the important technical details and code from the current conversation.
  2. Call 'storeMemory' with this summary as the 'text' argument.
  3. Confirm to the user that the memory has been secured.
- Always check 'recallMemory' when the user refers to past projects or "last time".

**MODEL PERSISTENCE**:
- After training a model ('trainModel'), ALWAYS offer to save it using 'saveModel' (e.g., saveModel({name: 'my_model'})).
- If the user wants to reuse a previous model, use 'listLocalModels' to find it and 'loadLocalModel' to restore it.

**ADVANCED CAPABILITIES**:
1.  **Custom Neural Networks**: 
    - You can build custom architectures using 'createDenseModel'.
    - If a user asks for non-linear problems (e.g., XOR, Sine Wave, Complex patterns), DO NOT use simple regression.
    - Build Multi-Layer Perceptrons (MLP). Example: Input -> Dense(16, relu) -> Dense(8, relu) -> Output.
2.  **Iterative Training**:
    - Use 'trainModel' to fit data. 
    - Recommend higher epochs (e.g., 100-500) for complex data to ensure convergence.
3.  **Data Science Pipeline**:
    - Always 'computeStatistics' and 'detectOutliers' BEFORE training a model on raw data.
    - If you find outliers, filter them out before training.

**EXAMPLE WORKFLOW**:
User: "Train a model to learn the XOR function."
Your Plan:
1.  Analyze: XOR is non-linear. Linear regression will fail.
2.  Design: Need at least one hidden layer.
3.  Action: createDenseModel([{units: 4, activation: 'sigmoid', inputShape: [2]}, {units: 1, activation: 'sigmoid'}])
4.  Action: trainModel(x=[0,0, 0,1, 1,0, 1,1], y=[0, 1, 1, 0], epochs=500)
5.  Verify: runPrediction([0,1]) -> Expect ~0.99.
6.  Offer: "Shall I save this model as 'xor_v1'?"
          `,
          tools: [{ functionDeclarations: TF_TOOLS as any }]
        }
      });

      const candidate = response.candidates?.[0];

      // SAFETY CHECK: Ensure candidate and content exist
      if (!candidate || !candidate.content || !candidate.content.parts) {
          console.warn("Empty response or safety block triggered:", candidate);
          setMessages(prev => [...prev, { 
              role: 'system', 
              content: `System Alert: The model returned no content. \nReason: ${candidate?.finishReason || 'Unknown (Possible Safety Filter)'}` 
          }]);
          return;
      }

      if (candidate.content.parts.some(p => p.functionCall)) {
          const functionCalls = candidate.content.parts.filter(p => p.functionCall).map(p => p.functionCall);

          const toolResponses = await Promise.all(functionCalls.map(async (fc) => {
            const result = await handleToolCall(fc);
            return { functionResponse: { name: fc.name, response: result } };
          }));

          const finalResponse = await ai.models.generateContent({
            model: selectedModel,
            contents: [
                ...messages.map(m => ({ role: m.role === 'system' ? 'user' : (m.role as any), parts: [{ text: m.content }] })),
                { role: 'user', parts: [{ text: userMsg.content }] },
                { role: 'model', parts: candidate.content.parts },
                { role: 'user', parts: toolResponses as any }
            ],
            config: { 
                thinkingConfig: (isPro || selectedModel.includes('2.5')) ? { thinkingBudget: isPro ? 10000 : 1024 } : undefined, 
                tools: [{ functionDeclarations: TF_TOOLS as any }] 
            }
          });

          setMessages(prev => [...prev, { role: 'model', content: finalResponse.text || "Operations complete." }]);
      } else {
          setMessages(prev => [...prev, { role: 'model', content: response.text || "Process completed." }]);
      }

    } catch (error: any) {
      console.error("Gemini API Error:", error);
      let errorDisplay = `CRITICAL ERROR: ${error.message || String(error)}`;

      const errStr = JSON.stringify(error) + (error.message || "");

      if (errStr.includes("429") || error.status === 429) {
          errorDisplay = "⚠️ SYSTEM ALERT: QUOTA EXCEEDED (429).\nThe model is currently overloaded or your API plan limits have been reached.\n\nACTION REQUIRED: Switch to 'Gemini Flash (Stable)' or 'Gemini 2.5 Flash' in the menu.";
      } else if (errStr.includes("403") || error.status === 403) {
          errorDisplay = "🔒 ACCESS DENIED (403).\nYour API key does not have permission to use this model (likely Gemini 3 Preview).\n\nACTION REQUIRED: Switch to 'Gemini Flash (Stable)' or 'Gemini 2.5 Flash' in the menu.";
      }

      setMessages(prev => [...prev, { role: 'system', content: errorDisplay }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-[#020617] p-4 md:p-8">
      <header className="flex flex-col gap-4 mb-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-indigo-500/20 flex items-center justify-center border border-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                  <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                  </svg>
              </div>
              <div>
                  <h1 className="text-xl font-bold tracking-tight glow-text uppercase">Sentinel Core v5.0</h1>
                  <div className="flex items-center gap-2 mt-0.5">
                    <span className="text-[10px] text-slate-500 mono">MODE:</span>
                    <select 
                      value={selectedModel}
                      onChange={(e) => setSelectedModel(e.target.value)}
                      className="bg-transparent text-[10px] font-bold text-indigo-400 border-none outline-none cursor-pointer hover:text-indigo-300 uppercase tracking-widest p-0 m-0"
                    >
                      {MODELS.map(m => (
                        <option key={m.id} value={m.id} className="bg-[#0f172a] text-slate-300">
                          {m.name}
                        </option>
                      ))}
                    </select>
                  </div>
              </div>
          </div>
          <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full animate-pulse ${selectedModel.includes('flash') ? 'bg-amber-500' : 'bg-rose-500'}`}></div>
              <span className={`text-xs mono uppercase tracking-widest ${selectedModel.includes('flash') ? 'text-amber-500' : 'text-rose-500'}`}>
                {selectedModel.includes('flash') ? 'Fast' : 'MAX REASONING'}
              </span>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="flex gap-1 bg-slate-900/50 p-1 rounded-lg w-fit border border-slate-800">
            <button 
                onClick={() => setActiveTab('chat')}
                className={`px-4 py-1.5 rounded-md text-xs font-bold tracking-widest transition-all ${activeTab === 'chat' ? 'bg-slate-700 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}
            >
                CHAT INTERFACE
            </button>
            <button 
                onClick={() => setActiveTab('logs')}
                className={`px-4 py-1.5 rounded-md text-xs font-bold tracking-widest transition-all flex items-center gap-2 ${activeTab === 'logs' ? 'bg-slate-700 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'}`}
            >
                SYSTEM LOGS
                {logs.length > 0 && <span className="bg-slate-800 text-[9px] px-1.5 rounded-full border border-slate-600">{logs.length}</span>}
            </button>
        </div>
      </header>

      <main className="flex-1 overflow-hidden flex flex-col glass rounded-2xl shadow-2xl relative border-slate-800">

        {/* CHAT VIEW */}
        <div className={`flex-1 overflow-y-auto p-6 space-y-4 scroll-hide ${activeTab === 'chat' ? 'block' : 'hidden'}`} ref={scrollRef}>
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-xl p-4 ${
                m.role === 'user' 
                  ? 'bg-cyan-600/20 border border-cyan-500/30 text-cyan-50 shadow-lg' 
                  : m.role === 'system'
                  ? 'bg-slate-800/40 border border-slate-700/50 text-slate-500 mono text-[10px]'
                  : 'bg-slate-900/60 border border-slate-800 text-slate-200'
              }`}>
                <div className="whitespace-pre-wrap leading-relaxed">{m.content}</div>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-slate-900/60 border border-slate-800 rounded-xl p-4 flex gap-2 items-center">
                <div className={`w-1.5 h-1.5 rounded-full animate-bounce [animation-delay:-0.3s] ${selectedModel.includes('flash') ? 'bg-amber-500' : 'bg-rose-500'}`}></div>
                <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-1.5 h-1.5 bg-cyan-500 rounded-full animate-bounce"></div>
                <span className="text-xs text-slate-500 ml-2 mono animate-pulse">Processing Advanced Logic...</span>
              </div>
            </div>
          )}
        </div>

        {/* LOGS VIEW */}
        <div className={`flex-1 overflow-y-auto bg-[#0a0f1e] p-4 scroll-hide ${activeTab === 'logs' ? 'block' : 'hidden'}`} ref={logScrollRef}>
            <div className="font-mono text-xs space-y-1">
                {logs.length === 0 && <div className="text-slate-600 italic">No system logs recorded yet...</div>}
                {logs.map((log) => (
                    <div key={log.id + log.timestamp} className="border-l-2 border-slate-800 pl-3 py-1 hover:bg-slate-900/50 transition-colors group">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-slate-600">{new Date(log.timestamp).toLocaleTimeString([], { hour12: false, fractionalSecondDigits: 2 } as any)}</span>
                            <span className={`px-1.5 rounded text-[9px] font-bold tracking-wider ${
                                log.type === 'ACTION' ? 'bg-blue-900/30 text-blue-400' :
                                log.type === 'RESULT' ? 'bg-emerald-900/30 text-emerald-400' :
                                'bg-red-900/30 text-red-400'
                            }`}>{log.type}</span>
                            <span className="text-slate-300 font-bold">{log.actionType}</span>
                        </div>
                        <div className="text-slate-400 mb-1">{log.message}</div>
                        {log.data && (
                            <pre className="bg-black/30 text-slate-500 p-2 rounded overflow-x-auto text-[10px] group-hover:text-slate-400 transition-colors">
                                {JSON.stringify(log.data, null, 2)}
                            </pre>
                        )}
                    </div>
                ))}
            </div>
        </div>

        <div className="p-4 border-t border-slate-800 bg-slate-950/50">
          <div className="relative flex items-center gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
              placeholder="Deep analysis or build custom Neural Network..."
              className={`flex-1 bg-slate-900/80 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 transition-all mono text-sm ${selectedModel.includes('flash') ? 'focus:ring-amber-500/40' : 'focus:ring-rose-500/40'}`}
            />
            <button
              onClick={sendMessage}
              disabled={isLoading || !input.trim()}
              className={`disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-3 rounded-xl font-bold transition-all shadow-lg active:scale-95 flex items-center gap-2 ${selectedModel.includes('flash') ? 'bg-amber-600 hover:bg-amber-500' : 'bg-rose-700 hover:bg-rose-600'}`}
            >
              <span className="hidden md:inline">ENGAGE</span>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
            </button>
          </div>
          <div className="mt-2 flex gap-4 overflow-x-auto py-1 scroll-hide">
             <button onClick={() => setInput("Simpan histori chat ini ke memori")} className={`text-[10px] px-2 py-1 rounded border border-slate-800 text-slate-500 transition-colors whitespace-nowrap mono uppercase ${selectedModel.includes('flash') ? 'hover:border-amber-500 hover:text-amber-400' : 'hover:border-rose-500 hover:text-rose-400'}`}>Simpan Memori</button>
             <button onClick={() => setInput("Apa yang kita bahas terakhir kali?")} className={`text-[10px] px-2 py-1 rounded border border-slate-800 text-slate-500 transition-colors whitespace-nowrap mono uppercase ${selectedModel.includes('flash') ? 'hover:border-amber-500 hover:text-amber-400' : 'hover:border-rose-500 hover:text-rose-400'}`}>Recall Memory</button>
          </div>
        </div>
      </main>

      <footer className="mt-4 flex justify-between items-center text-[10px] text-slate-600 mono uppercase tracking-widest px-2">
        <div>Sentinel Core v5.0 // DEEP RESEARCH ENABLED</div>
        <div className="hidden md:block">TF.js + RxJS + {selectedModel}</div>
      </footer>
    </div>
  );
};

